1.solution:
def count_char(s, c):
    count = 0
    for ch in s:
        if ch == c:
            count += 1
    return count

2.solution:
def reverse_string(s):
    reversed_str = ''
    for i in range(len(s) - 1, -1, -1):
        reversed_str += s[i]
    return reversed_str

3.solution:
def is_anagram(s1, s2):
    char_count = {}
    for ch in s1:
        char_count[ch] = char_count.get(ch, 0) + 1
    for ch in s2:
        if ch not in char_count or char_count[ch] == 0:
            return False
        char_count[ch] -= 1
    return all(count == 0 for count in char_count.values())

4.solution:
def sum_of_evens(nums):
    total = 0
    for n in nums:
        if n % 2 == 0:
            total += n
    return total

5.solution:
def second_largest(nums):
    nums.sort()
    largest = nums[-1]

    for i in range(len(nums) - 2, -1, -1):
        if nums[i] != largest:
            return nums[i]

    return -1

6.solution:
def merge_sorted(list1, list2):
    result = []
    i = 0
    j = 0

    while i < len(list1) and j < len(list2):
        if list1[i] <= list2[j]:
            result.append(list1[i])
            i += 1
        else:
            result.append(list2[j])
            j += 1

    while i < len(list1):
        result.append(list1[i])
        i += 1

    while j < len(list2):
        result.append(list2[j])
        j += 1

    return result

7.solution:
def sum_nested(matrix):
    total = 0

    for row in matrix:
        for num in row:
            total += num

    return total

8.solution:
def max_each_row(matrix):
    result = []

    for row in matrix:
        maximum = row[0]

        for num in row:
            if num > maximum:
                maximum = num

        result.append(maximum)

    return result

9.solution:
def transpose_matrix(matrix):
    if matrix == []:
        return []

    rows = len(matrix)
    cols = len(matrix[0])
    result = []

    for j in range(cols):
        new_row = []

        for i in range(rows):
            new_row.append(matrix[i][j])

        result.append(new_row)

    return result
